// 扫描线通用模板
struct Event {
    int pos;      // 事件位置（坐标/时间）
    int type;     // 事件类型（如+1表示区间开始，-1表示区间结束）
    int data;     // 附加数据（可选）
    bool operator<(const Event& other) const {
        // 优先按位置排序，相同位置时通常结束事件在前（type小的在前）
        return pos < other.pos || (pos == other.pos && type < other.type);
    }
};

void sweepLine(vector<pair<int, int>>& intervals, int k) {
    vector<Event> events;
    for (auto& [l, r] : intervals) {
        events.push_back({l, 1});   // 区间开始
        events.push_back({r, -1});  // 区间结束
    }
    sort(events.begin(), events.end());

    int cnt = 0;          // 当前覆盖数
    int ans = 0;          // 答案
    int lastPos = -1e9;   // 上一个事件位置

    for (auto& e : events) {
        // 处理上一个区间段的统计
        if (cnt >= k) {
            ans += e.pos - lastPos;  // 累计满足条件的长度
        }

        cnt += e.type;    // 更新覆盖计数
        lastPos = e.pos;  // 更新位置
    }

    // 输出答案
    cout << ans << endl;
}

