def solve_binary_sequence(n, k):
    # 1. 将n表示为二进制，统计每个幂次的出现次数
    cnt = [0] * MAX_BIT
    for i in range(MAX_BIT):
        if n >> i & 1:
            cnt[i] += 1

    # 2. 贪心从高位向低位分解（或从低位向高位合并）
    total = sum(cnt)
    for i in range(MAX_BIT - 1, 0, -1):
        while cnt[i] > 0 and total < k:
            cnt[i] -= 1
            cnt[i-1] += 2
            total += 1

    # 3. 检查是否满足条件并输出结果
    if total == k:
        result = []
        for i in range(MAX_BIT):
            result.extend([i] * cnt[i])
        return result
    else:
        return None

